import React from 'react';
import { Book, Clock, MoreVertical } from 'lucide-react';
import { Novel } from '../types/Novel';

interface NovelTableProps {
  novels: Novel[];
  onRowClick?: (novel: Novel) => void;
}

const statusMap: Record<string, { label: string; color: string }> = {
  reading: { label: '阅读中', color: 'bg-blue-100 text-blue-700' },
  completed: { label: '已完成', color: 'bg-green-100 text-green-700' },
  paused: { label: '已暂停', color: 'bg-yellow-100 text-yellow-700' },
  unread: { label: '未读', color: 'bg-gray-100 text-gray-700' },
};

export default function NovelTable({ novels, onRowClick }: NovelTableProps) {
  if (!novels?.length) {
    return (
      <div className="text-center py-12 text-gray-500">
        <Book className="h-12 w-12 mx-auto mb-4 opacity-50" />
        <p>暂无小说数据</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full">
        <thead>
          <tr className="border-b border-gray-200">
            <th className="text-left py-3 px-4 font-medium text-gray-600">书名</th>
            <th className="text-left py-3 px-4 font-medium text-gray-600">作者</th>
            <th className="text-left py-3 px-4 font-medium text-gray-600">进度</th>
            <th className="text-left py-3 px-4 font-medium text-gray-600">状态</th>
            <th className="text-left py-3 px-4 font-medium text-gray-600">最后阅读</th>
            <th className="w-10"></th>
          </tr>
        </thead>
        <tbody>
          {novels.map((novel) => {
            const status = statusMap[novel.status] || statusMap.unread;
            return (
              <tr
                key={novel.id}
                onClick={() => onRowClick?.(novel)}
                className="border-b border-gray-100 hover:bg-gray-50 cursor-pointer transition-colors"
              >
                <td className="py-3 px-4">
                  <div className="flex items-center gap-3">
                    <img src={novel.coverImage} alt={novel.title} className="w-10 h-14 object-cover rounded" />
                    <span className="font-medium text-gray-900">{novel.title}</span>
                  </div>
                </td>
                <td className="py-3 px-4 text-gray-600">{novel.author}</td>
                <td className="py-3 px-4">
                  <div className="flex items-center gap-2">
                    <div className="w-24 h-2 bg-gray-200 rounded-full overflow-hidden">
                      <div className="h-full bg-blue-500 rounded-full" style={{ width: `${novel.progressPercentage}%` }} />
                    </div>
                    <span className="text-sm text-gray-500">{novel.progressPercentage.toFixed(0)}%</span>
                  </div>
                </td>
                <td className="py-3 px-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-medium ${status.color}`}>{status.label}</span>
                </td>
                <td className="py-3 px-4 text-gray-500 text-sm">
                  <div className="flex items-center gap-1">
                    <Clock className="h-3 w-3" />
                    {new Date(novel.lastReadAt).toLocaleDateString('zh-CN')}
                  </div>
                </td>
                <td className="py-3 px-4">
                  <button className="p-1 hover:bg-gray-100 rounded">
                    <MoreVertical className="h-4 w-4 text-gray-400" />
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

import React from 'react';
import { Filter } from 'lucide-react';

interface FilterPanelProps {
  currentStatus: string;
  onStatusChange?: (status: string) => void;
}

const statusOptions = [
  { value: 'all', label: '全部' },
  { value: 'reading', label: '阅读中' },
  { value: 'completed', label: '已完成' },
  { value: 'paused', label: '已暂停' },
  { value: 'unread', label: '未读' },
];

export default function FilterPanel({ currentStatus, onStatusChange }: FilterPanelProps) {
  return (
    <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-lg">
      <div className="flex items-center gap-2 text-gray-600">
        <Filter className="h-4 w-4" />
        <span className="text-sm font-medium">筛选</span>
      </div>
      <div className="flex gap-2">
        {statusOptions.map((option) => (
          <button
            key={option.value}
            onClick={() => onStatusChange?.(option.value)}
            className={`px-3 py-1.5 text-sm rounded-lg transition-colors ${
              currentStatus === option.value
                ? 'bg-blue-600 text-white'
                : 'bg-white text-gray-600 hover:bg-gray-100 border border-gray-200'
            }`}
          >
            {option.label}
          </button>
        ))}
      </div>
    </div>
  );
}

import React from 'react';
import { BookOpen, Clock, TrendingUp } from 'lucide-react';
import { Novel } from '../types/Novel';

interface ReadingProgressCardProps {
  novel: Novel;
}

export default function ReadingProgressCard({ novel }: ReadingProgressCardProps) {
  if (!novel) return null;

  const pagesRemaining = novel.totalPages - novel.currentPage;
  const estimatedMinutes = pagesRemaining * 2;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <TrendingUp className="h-5 w-5 text-blue-500" />
        阅读进度
      </h3>
      <div className="space-y-4">
        <div>
          <div className="flex justify-between text-sm mb-2">
            <span className="text-gray-500">当前进度</span>
            <span className="font-medium text-gray-900">{novel.progressPercentage.toFixed(1)}%</span>
          </div>
          <div className="h-3 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-gradient-to-r from-blue-500 to-blue-600 rounded-full" style={{ width: `${novel.progressPercentage}%` }} />
          </div>
        </div>
        <div className="grid grid-cols-2 gap-4">
          <div className="p-3 bg-gray-50 rounded-lg">
            <div className="flex items-center gap-2 text-gray-500 text-sm mb-1">
              <BookOpen className="h-4 w-4" />
              已读页数
            </div>
            <div className="text-xl font-bold text-gray-900">{novel.currentPage}</div>
          </div>
          <div className="p-3 bg-gray-50 rounded-lg">
            <div className="flex items-center gap-2 text-gray-500 text-sm mb-1">
              <Clock className="h-4 w-4" />
              预计剩余
            </div>
            <div className="text-xl font-bold text-gray-900">{Math.round(estimatedMinutes / 60)}h {estimatedMinutes % 60}m</div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { StickyNote, ChevronRight } from 'lucide-react';
import { ReadingNote } from '../types/ReadingNote';

interface RecentNotesProps {
  notes: ReadingNote[];
  onViewAll?: () => void;
}

export default function RecentNotes({ notes, onViewAll }: RecentNotesProps) {
  const displayNotes = notes?.slice(0, 5) || [];

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold text-gray-900 flex items-center gap-2">
          <StickyNote className="h-5 w-5 text-amber-500" />
          最近笔记
        </h3>
        {onViewAll && (
          <button onClick={onViewAll} className="text-sm text-blue-600 hover:text-blue-700 flex items-center gap-1">
            查看全部 <ChevronRight className="h-4 w-4" />
          </button>
        )}
      </div>
      {displayNotes.length === 0 ? (
        <p className="text-gray-500 text-center py-8">暂无笔记</p>
      ) : (
        <div className="space-y-3">
          {displayNotes.map((note) => (
            <div key={note.id} className="p-3 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors cursor-pointer">
              <div className="text-sm text-gray-900 line-clamp-2">{note.content}</div>
              <div className="flex items-center gap-2 mt-2 text-xs text-gray-500">
                <span>第 {note.pageNumber} 页</span>
                <span>·</span>
                <span>{new Date(note.createdAt).toLocaleDateString('zh-CN')}</span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

