import React, { useState } from 'react';
import { BookPlus, Upload } from 'lucide-react';

interface NovelFormCardProps {
  onSubmit?: (data: { title: string; author: string; description: string }) => void;
}

export default function NovelFormCard({ onSubmit }: NovelFormCardProps) {
  const [title, setTitle] = useState('');
  const [author, setAuthor] = useState('');
  const [description, setDescription] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit?.({ title, author, description });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-6 flex items-center gap-2">
        <BookPlus className="h-5 w-5 text-blue-500" />
        添加新小说
      </h3>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">书名</label>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none"
            placeholder="请输入书名"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">作者</label>
          <input
            type="text"
            value={author}
            onChange={(e) => setAuthor(e.target.value)}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none"
            placeholder="请输入作者名"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">简介</label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={3}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none resize-none"
            placeholder="请输入小说简介"
          />
        </div>
        <div className="border-2 border-dashed border-gray-200 rounded-lg p-6 text-center">
          <Upload className="h-8 w-8 text-gray-400 mx-auto mb-2" />
          <p className="text-sm text-gray-500">点击或拖拽上传小说文件</p>
        </div>
        <button
          type="submit"
          className="w-full py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
        >
          添加小说
        </button>
      </form>
    </div>
  );
}

import React, { useState } from 'react';
import { PenLine } from 'lucide-react';

interface NoteFormCardProps {
  pageNumber?: number;
  onSubmit?: (data: { content: string; pageNumber: number }) => void;
}

export default function NoteFormCard({ pageNumber = 1, onSubmit }: NoteFormCardProps) {
  const [content, setContent] = useState('');
  const [page, setPage] = useState(pageNumber);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (content.trim()) {
      onSubmit?.({ content, pageNumber: page });
      setContent('');
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <PenLine className="h-5 w-5 text-amber-500" />
        添加笔记
      </h3>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">页码</label>
          <input
            type="number"
            value={page}
            onChange={(e) => setPage(Number(e.target.value))}
            min={1}
            className="w-24 px-3 py-2 border border-gray-200 rounded-lg focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">笔记内容</label>
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            rows={4}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:border-blue-500 focus:ring-1 focus:ring-blue-500 outline-none resize-none"
            placeholder="写下你的阅读心得..."
          />
        </div>
        <button
          type="submit"
          className="w-full py-2.5 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-colors font-medium"
        >
          保存笔记
        </button>
      </form>
    </div>
  );
}

import React, { useState } from 'react';
import { Type, Sun, Moon, BookOpen, Bookmark, Settings } from 'lucide-react';

interface ReadingToolbarProps {
  onFontSizeChange?: (size: number) => void;
  onThemeChange?: (theme: 'light' | 'dark' | 'sepia') => void;
  onAddBookmark?: () => void;
}

export default function ReadingToolbar({ onFontSizeChange, onThemeChange, onAddBookmark }: ReadingToolbarProps) {
  const [fontSize, setFontSize] = useState(16);
  const [theme, setTheme] = useState<'light' | 'dark' | 'sepia'>('light');

  const handleFontSizeChange = (delta: number) => {
    const newSize = Math.max(12, Math.min(24, fontSize + delta));
    setFontSize(newSize);
    onFontSizeChange?.(newSize);
  };

  const handleThemeChange = (newTheme: 'light' | 'dark' | 'sepia') => {
    setTheme(newTheme);
    onThemeChange?.(newTheme);
  };

  return (
    <div className="flex items-center gap-4">
      <div className="flex items-center gap-2">
        <button className="p-2 hover:bg-gray-100 rounded-lg" title="目录">
          <BookOpen className="h-5 w-5 text-gray-600" />
        </button>
        <button onClick={onAddBookmark} className="p-2 hover:bg-gray-100 rounded-lg" title="添加书签">
          <Bookmark className="h-5 w-5 text-gray-600" />
        </button>
      </div>
      <div className="flex items-center gap-1 bg-gray-100 rounded-lg p-1">
        <button onClick={() => handleFontSizeChange(-2)} className="px-2 py-1 hover:bg-white rounded text-gray-600">
          <Type className="h-4 w-4" />
        </button>
        <span className="px-2 text-sm text-gray-600">{fontSize}</span>
        <button onClick={() => handleFontSizeChange(2)} className="px-2 py-1 hover:bg-white rounded text-gray-600">
          <Type className="h-5 w-5" />
        </button>
      </div>
      <div className="flex items-center gap-1 bg-gray-100 rounded-lg p-1">
        <button onClick={() => handleThemeChange('light')} className={`p-1.5 rounded ${theme === 'light' ? 'bg-white shadow-sm' : ''}`}>
          <Sun className="h-4 w-4 text-gray-600" />
        </button>
        <button onClick={() => handleThemeChange('sepia')} className={`p-1.5 rounded ${theme === 'sepia' ? 'bg-white shadow-sm' : ''}`}>
          <span className="w-4 h-4 block rounded-full bg-amber-100 border border-amber-200" />
        </button>
        <button onClick={() => handleThemeChange('dark')} className={`p-1.5 rounded ${theme === 'dark' ? 'bg-white shadow-sm' : ''}`}>
          <Moon className="h-4 w-4 text-gray-600" />
        </button>
      </div>
      <button className="p-2 hover:bg-gray-100 rounded-lg">
        <Settings className="h-5 w-5 text-gray-600" />
      </button>
    </div>
  );
}

import React from 'react';

interface ProgressSliderProps {
  currentPage: number;
  totalPages: number;
  onChange?: (page: number) => void;
}

export default function ProgressSlider({ currentPage, totalPages, onChange }: ProgressSliderProps) {
  const percentage = totalPages > 0 ? (currentPage / totalPages) * 100 : 0;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(Number(e.target.value));
  };

  return (
    <div className="p-4 bg-white border-t border-gray-200">
      <div className="flex items-center gap-4">
        <span className="text-sm text-gray-500 w-16">{currentPage} 页</span>
        <div className="flex-1 relative">
          <input
            type="range"
            min={1}
            max={totalPages}
            value={currentPage}
            onChange={handleChange}
            className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
          <div className="absolute top-1/2 -translate-y-1/2 left-0 h-2 bg-blue-500 rounded-l-lg pointer-events-none" style={{ width: `${percentage}%` }} />
        </div>
        <span className="text-sm text-gray-500 w-16 text-right">{totalPages} 页</span>
      </div>
      <div className="text-center mt-2 text-sm text-gray-400">{percentage.toFixed(1)}% 已读</div>
    </div>
  );
}

import React from 'react';
import { Clock, BookOpen, Calendar, TrendingUp } from 'lucide-react';
import { ReadingSession } from '../types/ReadingSession';

interface ReadingStatsProps {
  sessions: ReadingSession[];
}

export default function ReadingStats({ sessions }: ReadingStatsProps) {
  const data = sessions || [];
  const totalDuration = data.reduce((sum, s) => sum + s.duration, 0);
  const totalPages = data.reduce((sum, s) => sum + (s.endPage - s.startPage), 0);
  const sessionCount = data.length;
  const avgDuration = sessionCount > 0 ? Math.round(totalDuration / sessionCount / 60) : 0;

  const stats = [
    { icon: Clock, label: '总阅读时长', value: `${Math.round(totalDuration / 3600)}h ${Math.round((totalDuration % 3600) / 60)}m`, color: 'text-blue-500 bg-blue-50' },
    { icon: BookOpen, label: '已读页数', value: `${totalPages} 页`, color: 'text-green-500 bg-green-50' },
    { icon: Calendar, label: '阅读次数', value: `${sessionCount} 次`, color: 'text-purple-500 bg-purple-50' },
    { icon: TrendingUp, label: '平均时长', value: `${avgDuration} 分钟`, color: 'text-amber-500 bg-amber-50' },
  ];

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">阅读统计</h3>
      <div className="grid grid-cols-2 gap-4">
        {stats.map((stat) => (
          <div key={stat.label} className="p-4 rounded-lg bg-gray-50">
            <div className={`inline-flex p-2 rounded-lg ${stat.color} mb-2`}>
              <stat.icon className="h-5 w-5" />
            </div>
            <div className="text-2xl font-bold text-gray-900">{stat.value}</div>
            <div className="text-sm text-gray-500">{stat.label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

import React from 'react';
import { Clock, ChevronRight } from 'lucide-react';
import { Novel } from '../types/Novel';

interface RecentNovelsProps {
  novels: Novel[];
  onNovelClick?: (novel: Novel) => void;
}

export default function RecentNovels({ novels, onNovelClick }: RecentNovelsProps) {
  const recentNovels = (novels || [])
    .filter(n => n.status === 'reading')
    .sort((a, b) => new Date(b.lastReadAt).getTime() - new Date(a.lastReadAt).getTime())
    .slice(0, 4);

  if (recentNovels.length === 0) {
    return (
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">继续阅读</h3>
        <p className="text-gray-500 text-center py-8">暂无正在阅读的小说</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">继续阅读</h3>
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {recentNovels.map((novel) => (
          <div
            key={novel.id}
            onClick={() => onNovelClick?.(novel)}
            className="group cursor-pointer"
          >
            <div className="relative aspect-[3/4] rounded-lg overflow-hidden mb-2">
              <img src={novel.coverImage} alt={novel.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
              <div className="absolute inset-x-0 bottom-0 h-1 bg-gray-200">
                <div className="h-full bg-blue-500" style={{ width: `${novel.progressPercentage}%` }} />
              </div>
            </div>
            <h4 className="font-medium text-gray-900 text-sm truncate">{novel.title}</h4>
            <div className="flex items-center gap-1 text-xs text-gray-500">
              <Clock className="h-3 w-3" />
              <span>{new Date(novel.lastReadAt).toLocaleDateString('zh-CN')}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import React from 'react';
import { Tag } from 'lucide-react';
import { Category } from '../types/Category';

interface CategoryOverviewProps {
  categories: Category[];
  onCategoryClick?: (category: Category) => void;
}

export default function CategoryOverview({ categories, onCategoryClick }: CategoryOverviewProps) {
  const displayCategories = categories || [];

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <Tag className="h-5 w-5 text-purple-500" />
        分类浏览
      </h3>
      {displayCategories.length === 0 ? (
        <p className="text-gray-500 text-center py-8">暂无分类</p>
      ) : (
        <div className="flex flex-wrap gap-2">
          {displayCategories.map((category) => (
            <button
              key={category.id}
              onClick={() => onCategoryClick?.(category)}
              className="px-4 py-2 rounded-full text-sm font-medium transition-colors hover:opacity-80"
              style={{ backgroundColor: `${category.color}15`, color: category.color }}
            >
              {category.name}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}
